export function plinkoMultipliers(risk: PlinkoRisk, rows: number): number[] {
  return PLINKO_TABLES[risk][rows] ?? PLINKO_TABLES[risk][PLINKO_MAX_ROWS];
}

// Bucket colour: hot at the high-paying edges, cool toward the centre — the
// classic Stake red→amber→yellow gradient. `k` is the bucket index, `n` rows.
export function bucketColor(k: number, n: number): string {
  const t = Math.abs(k - n / 2) / (n / 2); // 0 centre … 1 edge
  // interpolate yellow (centre) → amber → red (edge)
  const stops = [
    [255, 210, 64], // #ffd240 centre
    [255, 145, 40], // #ff9128
    [244, 63, 94], // #f43f5e edge
  ];
  const seg = t >= 0.5 ? 1 : 0;
  const local = t >= 0.5 ? (t - 0.5) * 2 : t * 2;
  const a = stops[seg];
  const b = stops[seg + 1];
  const c = a.map((v, i) => Math.round(v + (b[i] - v) * local));
  return `rgb(${c[0]}, ${c[1]}, ${c[2]})`;
}
